class Solution {
public:
    vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        int maxScore = 0;
        vector<int> result;
        for (int i = 0; i <= n; ++i) {
            int leftZeros = 0;
            int rightOnes = 0;
            for (int j = 0; j < i; ++j) {
                if (nums[j] == 0) {
                    leftZeros++;
                }
            }
            for (int j = i; j < n; ++j) {
                if (nums[j] == 1) {
                    rightOnes++;
                }
            }
            int currentScore = leftZeros + rightOnes;
            if (currentScore > maxScore) {
                maxScore = currentScore;
                result.clear();
                result.push_back(i);
            } else if (currentScore == maxScore) {
                result.push_back(i);
            }
        }
        return result;
    }
};
